&GSD(\mathcal{P}, \mathcal{S}) = \Delta^{(n)}_{\text{mapped}} + \Delta^{(n)}_{\text{remain}} + \Delta^{(r)}_{\text{mapped}} + \Delta^{(r)}_{\text{remain}}, \\
&\Delta^{(n)}_{\text{mapped}}
= \sum_{\substack{\text{node } v_\mathcal{P} \in \mathcal{P} \\ \text{ mapped in } f}} \| z_{v_\mathcal{P}} - z_{f(v_\mathcal{P})} \|_2, \\ 
&\Delta^{(n)}_{\text{remain}} = \sum_{\substack{\text{node } v_\mathcal{P} \in \mathcal{P} \\ \text{ not mapped in } f}} \| z_{v_\mathcal{P}} - z_{f'(v_\mathcal{P})} \|_2, \\
&\Delta^{(r)}_{\text{mapped}} = \sum_{( h_\mathcal{P}, r_\mathcal{P}, t_\mathcal{P} ) \in L[1:i]} \| z_{r_\mathcal{P}} - z_{r_{\langle f(h_\mathcal{P}), f(t_\mathcal{P}) \rangle}} \|_2, \\
&\Delta^{(r)}_{\text{remain}} = \sum_{( h_\mathcal{P}, r_\mathcal{P}, t_\mathcal{P} ) \in L[i:]} \| z_{r_\mathcal{P}} - z_{r_{\langle f'(h_\mathcal{P}), f'(t_\mathcal{P}) \rangle}} \|_2.
\end{equation}

